import type { SidebarsConfig } from "@docusaurus/plugin-content-docs";

// The OpenAPI plugin generates a sidebar definition that uses category links
// with tag pages.  Importing it directly (instead of autogenerated) ensures
// the tag pages are recognised as category index pages so
// useCurrentSidebarCategory() works at build time.
import apiSidebar from "./docs/api/sidebar";

const sidebars: SidebarsConfig = {
  guidesSidebar: [
    {
      type: "doc",
      id: "intro",
      label: "Introduction",
    },
    {
      type: "category",
      label: "Guides",
      collapsed: false,
      items: [
        "api-guide",
        "model-store",
        "kv-cache-backends",
        "architecture",
      ],
    },
  ],

  apiSidebar,
};

export default sidebars;
